var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GUARD_DELTA_NULL_NULL","text":{"KOREA":"경비부대, 전원 집합했습니다.","JPN":"総員、集結しました。","ENG":"All of us guards are here.","TWN":"守衛部隊集合完畢。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"GUARD_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GUARD_DELTA_NULL_NULL","text":{"KOREA":"그리고 지시하셨던 대로 감시 카메라를 확인해 보았습니다.","JPN":"それから、ご指示どおり、監視カメラを確認してみました。","ENG":"And we've checked the surveillance cameras as you asked.","TWN":"按照您的指示，確認了監視器。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"GUARD_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GUARD_DELTA_NULL_NULL","text":{"KOREA":"믿기 어렵지만...... 침입자들은 반응로 근처에서 갑자기 나타난 것 같습니다.","JPN":"信じがたいですが……侵入者は反応炉の近くから突如現れたようです。","ENG":"This is hard to believe, but the intruders suddenly appeared near the reactor.","TWN":"雖然難以置信……但入侵者們好像是突然出現在反應爐周圍的。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"GUARD_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그렇다면......","JPN":"それなら……","ENG":"Then...","TWN":"這樣說來……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"역시 폭주한 반응로에서 방출된 에너지를 매개로 차원계면을 뚫고 나온 것 같군요.","JPN":"やはり暴走中の反応炉から放たれたエネルギーを媒介にして、次元界面を突破したようですね。","ENG":"They really must have come through the dimension surface because of the energy released from the overloaded reactor.","TWN":"果然是反應爐暴走後，釋放出的能量成為媒介，突破了次元邊界。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GUARD_DELTA_NULL_NULL","text":{"KOREA":"하지만 소령님, 이면세계를 떠돌다가 온 것 치고는 몸도 정신도 멀쩡해 보였습니다.","JPN":"ですが少佐、裏世界をさまよっていたわりには、肉体も精神もまともに見えました。","ENG":"But Major, they didn't look like they'd wandered about the Counterside. They looked too normal for that.","TWN":"但是少校，如果她們是從異界過來的，精神和肉體似乎都過於正常。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"GUARD_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"타당한 지적입니다. 그런 의문점들은 체포 후 심문 과정을 통해 알아낼 수 있을 겁니다.","JPN":"妥当な指摘です。そのような疑問は逮捕した後、尋問すれば突き止められるかと。","ENG":"I agree. We'll get answers to those questions once we capture them.","TWN":"你說的沒錯。這些疑問，你可以逮捕後親自問她們。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그보다 지원군 요청은 어떻게 됐습니까?","JPN":"それより、援軍要請の進捗はいかがですか？","ENG":"By the way, how goes the request for reinforcements?","TWN":"比起這個，我們請求增援的狀況怎麼樣了？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GUARD_DELTA_NULL_NULL","text":{"KOREA":"몇 차례 시도했지만 모두 실패로 돌아갔습니다.","JPN":"何度も試しましたが、すべて失敗におわりました。","ENG":"I've tried several times, but to no avail.","TWN":"我試了幾次，但全部都失敗了。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"GUARD_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GUARD_DELTA_NULL_NULL","text":{"KOREA":"아마도 반응로 폭주의 영향으로 장거리 통신이 방해 받고 있는 것 같습니다.","JPN":"おそらく反応炉の暴走により、長距離通信が正常に行えないようです。","ENG":"It seems the rampaging energy from the reactor is interrupting long-distance communication.","TWN":"似乎是受到爆炸的影響，遠端通訊遭到了干擾。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"GUARD_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그렇다면 더 이상의 연락 시도는 의미가 없겠군요.","JPN":"それならば、これ以上連絡しても意味がないでしょうね。","ENG":"Then, there's no use trying to use it.","TWN":"那就沒必要再嘗試了。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"일단 별동대를 편성해서 가장 가까운 기지로 보내세요. 시급히 상황을 전해야 합니다.","JPN":"まずは別動隊を編成して、最も近場の基地に派遣してください。至急この状況を伝えねば。","ENG":"Please send out a detached force to the nearest base. We must alert it of our situation.","TWN":"組織一個分隊派到最近的基地去，必須要立刻將這個緊急狀況上報。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GUARD_DELTA_NULL_NULL","text":{"KOREA":"예, 소령님!","JPN":"はい、少佐！","ENG":"Yes, Major.","TWN":"是，少校！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"GUARD_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"별동대를 제외한 전 병력은 현 시간부로 침입자를 찾기 위한 긴급 수색작전을 개시합니다!","JPN":"別動隊を除く全兵力は、これより侵入者を捜すための緊急捜索作戦を開始します！","ENG":"Everyone, except for the detached force, will start looking for the intruders.","TWN":"除了分隊以外，所有部隊現在開始進行緊急搜索作戰，找出入侵者！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"기밀 사항이 유출될 위험이 있는 만큼, 다들 서둘러 주십시오!","JPN":"機密漏えいの恐れがありますので、皆さん、急いでください！","ENG":"Let's hurry. Our classified information is at stake.","TWN":"因為有機密情報洩露的危險，請各位盡速行動！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이야, 잠깐 쉬는 동안 사람이 쫙 깔렸네요. 이래서야 한 발자국도 못 움직이겠어요.","JPN":"うひゃ～、一息ついてたらものすごい人数が集まりましたね。これじゃ、一歩も動けそうにありません。","ENG":"Wow, so many people came to look for us for the short time we took a break. We can't go anywhere now.","TWN":"哎呀，才休息一會兒就聚集了這麼多人。這樣我們連一步都動不了啊。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"충돌은 피할 수 없겠군요.","JPN":"衝突は避けられませんね。","ENG":"A clash is inevitable.","TWN":"無法避免衝突了呢。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};